class Solution {
    public int findTheLongestBalancedSubstring(String s) {
        int maxLength = 0;
        int countZero = 0;
        int countOne = 0;

        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '0') {
                countZero++;
            } else {
                countOne++;
            }

            if (countZero > countOne) {
                maxLength = i;
            }

            if (countZero == countOne) {
                break;
            }
        }

        return maxLength;
    }
}
